        public async Task<Candidate> GetByEmail(string email)
        {
            var candidate = await _entities.Where(x => x.Email.ToLower().Trim() == email.ToLower().Trim()).FirstOrDefaultAsync();

            return candidate;
        }

        public async Task<Candidate> GetByGuid(string guid)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateGuid == guid).FirstOrDefaultAsync();

            return candidate;
        }

        public new async Task<Candidate> GetById(int id)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == id)
                .Include(x => x.BasicInformation).FirstOrDefaultAsync();

            return candidate;
        }

        public async Task<List<Candidate>> GetPageSectionCandidate(int page, int pageSize, int userType, int companyUserId)
        {
            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt"};

            List<Candidate> candidatesList = new List<Candidate>();

            if (userType == 1)
            {
                candidatesList = await _entities.Where(x => x.CompanyUserId == companyUserId || (x.IsMigrated == 0 || x.IsFromCompanyAndLogin)).Include(x => x.BasicInformation)
                .AsNoTracking().ToListAsync();
            }
            else if (userType == 2)
            {
                candidatesList = await _entities.Where(x => x.CompanyUserId == companyUserId).Include(x => x.BasicInformation)
                .AsNoTracking().ToListAsync();
            }

            candidatesList = candidatesList.OrderByDescending(x => DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture)).ToList();

            List<Candidate> pageSources = candidatesList.Skip((page) * pageSize).Take(pageSize).ToList();

            return pageSources;
        }

