        {
            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt"};

            List<Candidate> candidatesList = await _entities.Include(x => x.BasicInformation)
                .Where(x => x.IsMigrated == 0 || (x.IsMigrated != 0 && x.IsFromCompanyAndLogin == true))
                .AsNoTracking().ToListAsync();

            candidatesList = candidatesList.OrderByDescending(x => DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture)).ToList();

            List<Candidate> pageSources = candidatesList.Skip((page) * pageSize).Take(pageSize).ToList();

            return pageSources;
        }

