        public async Task<int> CountAllCandidateMaster()
        {
            List<Candidate> candidatesList = await _entities.Include(x => x.BasicInformation)
               .Where(x => x.IsMigrated == 0 || (x.IsMigrated != 0 && x.IsFromCompanyAndLogin == true))
               .OrderByDescending(x => x.CandidateId)
               .AsNoTracking().ToListAsync();

            return candidatesList.Count;
        }


        public async Task<Candidate> GetCandidateProfileOverViewById(int candidateId)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.Language)
                .Include(x => x.LanguageOther)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(y => y.TechnicalAbilityLevel)
                .Include(x => x.Candidate_SoftSkillList).ThenInclude(y => y.SoftSkill)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.LanguageLevel)
                //.Include(x => x.BasicInformation)
                .FirstOrDefaultAsync();

            return candidate;
        }

