        public bool CandidateExist(Study study)
        {
            var response = _context.Candidate
                .Where(x => x.CandidateId == study.CandidateId).ToList();
            if (response.Count == 0)
            {
                return false;
            }
            return true;
        }

        public bool CandidateExistById(int candidateId)
        {
            var response = _context.Candidate
                .Where(x => x.CandidateId == candidateId).AsNoTracking().ToList();
            if (response.Count == 0)
            {
                return false;
            }
            return true;
        }

        public async Task<bool> CandidateExistByEmail(string email)
        {
            var response = await _context.Candidate
                .Where(x => x.Email.ToLower().Trim() == email.ToLower().Trim()).FirstOrDefaultAsync();

            if (response == null)
            {
                return false;
            }

            return true;
        }

        public async Task<bool> CandidateExistByEmailAndAlternativeEmails(string email)
        {
            var response = await _context.Candidate
                .Where(x => x.Email.ToLower().Trim() == email.ToLower().Trim() || x.BasicInformation.Emails.Any(y => y.Mail.ToLower().Trim() == email.ToLower().Trim())).FirstOrDefaultAsync();

            if (response == null)
            {
                return false;
            }

            return true;
        }

        public async Task<bool> CandidateExistByEmailAndSecondBigMigration(string email)
        {
            var response = await _context.Candidate
                .Where(x => x.Email.ToLower().Trim() == email.ToLower().Trim() &&
                (x.CreationDate.Contains("12/15/2022") || x.CreationDate.Contains("12/16/2022"))).FirstOrDefaultAsync();

            if (response == null)
            {
                return false;
            }

            return true;
        }

        public async Task<bool> AddMigration(Candidate entity)
        {
            try
            {
                var response = await _context.Candidate.Where(x => x.Email.ToLower().Trim() == entity.Email.ToLower().Trim()).FirstOrDefaultAsync();
                if (response != null)
                    return false;
                await _entities.AddAsync(entity);
                int states = await _context.SaveChangesAsync();

                if (states != 0)
                    return true;
                _entities.AsNoTracking();
                return false;
            }
            catch (Exception ex)
            {
                return false;
            }
        }

        /// <summary>
        /// Get Candidate Experience Counter - Years and Companies - By Candidate ID
        /// </summary>
        /// <param name="candidateId"></param>
        /// <returns></returns>
        public async Task<ExperienceCount> ExperienceCountByCandidateId(int candidateId)
        {
            ExperienceCount experienceCount = await _context.ExperienceCount
                .Where(x => x.CandidateId == candidateId)
                .FirstOrDefaultAsync();

            return experienceCount;
        }

        /// <summary>
        /// Add or Update Experience Count in DB
        /// </summary>
        /// <param name="experienceCount"></param>
        /// <returns></returns>
        public async Task<bool> AddExperienceCounter(ExperienceCount experienceCount)
        {
            // Search ExperienceCount in DB
            ExperienceCount _experienceCount = await _context.ExperienceCount
                .Where(x => x.CandidateId == experienceCount.CandidateId)
                .FirstOrDefaultAsync();

            if (_experienceCount != null)
            {
                // Update ExperienceCount if record exists
                _experienceCount.CompaniesNumber = experienceCount.CompaniesNumber;
                _experienceCount.Years = experienceCount.Years;
                _context.ExperienceCount.Update(_experienceCount);
                int states = await _context.SaveChangesAsync();

                if (states != 0)
                    return true;

                return false;
            }
            else
            {
                // Create ExperienceCount if record doesn't exists
                await _context.ExperienceCount.AddAsync(experienceCount);
                int states = await _context.SaveChangesAsync();

                if (states != 0)
                    return true;

                return false;
            }
        }

        public async Task<object[]> EditEditionDate(int candidateId)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId).FirstOrDefaultAsync();

            object[] ans = new object[2];
            ans[0] = false;
            ans[1] = "";

            if (candidate != null)
            {
                candidate.EditionDate = DateTime.Now.ToLocalTime().AddHours(-5).ToString();

                _context.Update(candidate);

                int states = await _context.SaveChangesAsync();

                if (states != 0)
                {
                    ans[0] = true;
                    ans[1] = candidate.EditionDate;
                }
            }

            return ans;
        }

