        public async Task<List<Candidate>> GetAllCandidatesFromCompany(int companyUserId)
        {
            List<Candidate> candidates = await _entities.Where(x => x.CompanyUserId == companyUserId).ToListAsync();

            return candidates;
        }

        public async Task<List<Candidate>> GetAllCandidatesFromCompanyOrMigrated(int companyUserId)
        {
            List<Candidate> candidates = await _entities.Where(x => x.CompanyUserId == companyUserId || (x.CompanyUserId == 0 && x.IsMigrated == 0)).ToListAsync();

            return candidates;
        }

        public async Task<int> CountAllCandidatesFromCompany(int companyUserId)
        {
            List<Candidate> candidates = await _entities.Where
            (
                candidate
                =>
                candidate.CompanyUserId == companyUserId
                ||
                (
                    (
                        candidate.Candidate_Postulation != null
                        &&
                        candidate.Candidate_Postulation.Count > 0
                    )
                    &&
                    candidate.Candidate_Postulation.Any
                    (
                       candidate_postulation => candidate_postulation.CompanyUserId == companyUserId
                       &&
                       (
                           candidate_postulation.JobPostingStatusId == 2
                           ||
                           candidate_postulation.JobPostingStatusId == 3
                       )
                    )
                )
            ).ToListAsync();

            int total = candidates.Count();

            return total;
        }

        public async Task<List<Candidate>> GetCandidatesByString(string search, int pageSize, int companyUserId, int userType)
        {
            if (!string.IsNullOrEmpty(search))
                search = search.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().TrimStart().TrimEnd();

            List<Candidate> candidatesList = new List<Candidate>();

            if (pageSize != 0)
            {
                if (userType == 0) // Master
                {                    
                    candidatesList = await _entities
                        .Include(x => x.BasicInformation)
                        .Where
                        (
                            c => 
                            (
                                c.IsMigrated == 0 ||
                                c.IsFromCompanyAndLogin
                            )
                            &&
                            (
                                c.Email.ToLower().Trim().Contains(search) ||
                                c.BasicInformation.Name.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().Contains(search)
                                ||
                                c.BasicInformation.Surname.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().Contains(search)
                                ||
                                (
                                    c.BasicInformation.Name.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().TrimEnd() 
                                    +
                                    " " 
                                    +
                                    c.BasicInformation.Surname.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().TrimEnd()
                                )
                                .Contains(search)
                            )
                        )
                    .OrderByDescending(c => c.CandidateId)
                    .Take(pageSize)
                    .AsNoTracking()
                    .ToListAsync();
                }
                if (userType == 1) // Exsis
                {
                    candidatesList = await _entities
                        .Include(x => x.BasicInformation)
                        .Where
                        (
                            c =>
                            (
                                (
                                    c.CompanyUserId == companyUserId ||
                                    c.IsMigrated == 0 ||
                                    c.IsFromCompanyAndLogin
                                )
                                ||
                                (
                                    c.Candidate_Postulation.Any
                                    (
                                        p => p.CompanyUserId == companyUserId && (p.JobPostingStatusId == 2 || p.JobPostingStatusId == 3)
                                    )
                                )
                            )
                            &&
                            (
                                c.Email.ToLower().Trim().Contains(search) ||
