                                c.BasicInformation.Name.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().Contains(search)
                                ||
                                c.BasicInformation.Surname.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().Contains(search)
                                ||
                                (
                                    c.BasicInformation.Name.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().TrimEnd()
                                    +
                                    " "
                                    +
                                    c.BasicInformation.Surname.Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").ToLower().TrimEnd()
                                )
                                .Contains(search)
                            )
                        )
                    .OrderByDescending(c => c.CandidateId)
                    .AsNoTracking()
                    .ToListAsync();
                }
            }

            return candidatesList;
        }

        public async Task<List<Candidate>> GetCandidatesByStringWithoutSearch(int companyUserId, int userType)
        {
            List<Candidate> candidatesList = new List<Candidate>();

            if (userType == 0) // Master
            {
                candidatesList = await _entities.Include(x => x.BasicInformation)
                .Where(x => (x.IsMigrated == 0 || x.IsFromCompanyAndLogin))
                .Include(x => x.CompanyDescriptionList)
                .OrderByDescending(x => x.CandidateId)
                .AsNoTracking()
                .ToListAsync();
            }
            if (userType == 1) // Exsis
            {
                candidatesList = await _entities.Include(x => x.BasicInformation)
                .Where(x => ((x.CompanyUserId == companyUserId || (x.IsMigrated == 0 || x.IsFromCompanyAndLogin))
                || x.Candidate_Postulation.Any(y => y.CompanyUserId == companyUserId && (y.JobPostingStatusId == 2 || y.JobPostingStatusId == 3))))
                .Include(x => x.CompanyDescriptionList)
                .OrderByDescending(x => x.CandidateId)
                .AsNoTracking()
                .ToListAsync();
            }
            if (userType == 2) // Otra empresa
            {
                candidatesList = await _entities.Include(x => x.BasicInformation)
                .Where(x => (x.CompanyUserId == companyUserId || x.Candidate_Postulation.Any(y => y.CompanyUserId == companyUserId && (y.JobPostingStatusId == 2 || y.JobPostingStatusId == 3))))
                .Include(x => x.CompanyDescriptionList)
                .OrderByDescending(x => x.CandidateId)
                .AsNoTracking()
                .ToListAsync();
            }

            return candidatesList;
        }

