        public async Task<List<Candidate>> GetCandidatesByFilterAndJobOrTalentGroupFullList(
            SearchByIdAndTextWithPaginationDTO searchObject,
            int companyUserId, List<int> candidatesIds)
        {
            List<Candidate> candidatesList = new List<Candidate>();

            /**/

            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt",
                                            "M/dd/yyyy HH:mm:ss", "M/d/yyyy HH:mm:ss", "MM/d/yyyy HH:mm:ss"};

            /**/

            try
            {
                searchObject.Text = searchObject.Text.ToLower().TrimStart().TrimEnd()
                .Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u");

                candidatesList = await _entities
                    .Where
                    (
                        x => candidatesIds.Any(y => y == x.CandidateId)
                    )
                    .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                    .Include(x => x.BasicInformation).ThenInclude(x => x.Phones)
                    .Include(x => x.Candidate_Language).ThenInclude(y => y.Language)
                    .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(y => y.TechnicalAbilityLevel)
                    .Include(x => x.StudyList)
                    .Include(x => x.CompanyDescriptionList)
                    .Include(x => x.CandidateCompanies)
                    .Include(x => x.WorkExperienceList)

                    .Where(x =>
                    x.Email.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(searchObject.Text)
                    || x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(searchObject.Text)
                    || x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(searchObject.Text)
                    || (x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd() + " " +
                    x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd()).Contains(searchObject.Text) || x.BasicInformation.Phone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(searchObject.Text)
                    || x.BasicInformation.Emails.Any(y => y.Mail.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(searchObject.Text))
                    )

                    .AsNoTracking()
                    .ToListAsync();

                if (candidatesList != null && candidatesList.Count > 0)
                {
                    foreach (Candidate candidate in candidatesList)
                    {
                        candidate.Candidate_Language = await _candidateLanguageRepository.GetByCandidateId(candidate.CandidateId);
                    }
                }

                candidatesList = candidatesList

                        .Where(x =>
                        /* Job Posting Status */
                        (
                            x.CompanyUserId == companyUserId
                            ||
                            (
                            x.Candidate_Postulation != null
                            &&
                            x.Candidate_Postulation.Any(y => y.CompanyUserId == companyUserId && (y.JobPostingStatusId == 2 || y.JobPostingStatusId == 3))
                            )
                        )
                        &&
                        /* Technology */
                        (
                           (
                                searchObject.TechnicalAbilities != null
                                &&
                                searchObject.TechnicalAbilities.Count > 0
                                &&
                                x.Candidate_TechnicalAbilityList != null
                                &&
                                x.Candidate_TechnicalAbilityList.Count > 0
                                &&
                                searchObject.TechnicalAbilities.All(t => x.Candidate_TechnicalAbilityList
                                    .Any(y => y.TechnicalAbilityTechnologyId == t.TechnicalAbilityTechnologyId && y.TechnicalAbilityLevelId == t.TechnicalAbilityLevelId))
                           )
                           ||
                           (
                               (
                                   searchObject.TechnicalAbilities == null
                                   ||
                                   searchObject.TechnicalAbilities.Count == 0
                               )
                           )
                        )
                    )
                    .ToList();

                if (!searchObject.Ascending)
                {
                    candidatesList = candidatesList
                    .OrderByDescending(x => DateTime.ParseExact(x.CreationDate.Replace(".", ""), validformats, CultureInfo.InvariantCulture, DateTimeStyles.None))
                    .Skip((searchObject.Page) * searchObject.PageSize).Take(searchObject.PageSize)
                    .ToList();
                }
                else
                {
                    candidatesList = candidatesList
                    .OrderBy(x => DateTime.ParseExact(x.CreationDate.Replace(".", ""), validformats, CultureInfo.InvariantCulture, DateTimeStyles.None))
                    .Skip((searchObject.Page) * searchObject.PageSize).Take(searchObject.PageSize)
                    .ToList();
                }

                return candidatesList;
            }
            catch (Exception ex)
            {
                return new List<Candidate>();
            }
        }

