                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).FirstOrDefault().YearsExperience)
                                                                            <=
                                                                            experienceUpperLimit
                                                                    )
                                                                )
                                                                ||
                                                                (
                                                                    (
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ) != null
                                                                        &&
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).Count() > 0
                                                                        &&
                                                                        culture.Name.Contains("es-")
                                                                        &&
                                                                        !string.IsNullOrEmpty
                                                                        (
                                                                            candidate.CompanyDescriptionList
                                                                            .Where
                                                                            (
                                                                                companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                            )
                                                                            .FirstOrDefault().YearsExperience
                                                                        )
                                                                        &&
                                                                        double.TryParse
                                                                        (
                                                                            candidate.CompanyDescriptionList
                                                                            .Where
                                                                            (
                                                                                companyDescription
                                                                                =>
                                                                                companyDescription.CompanyUserId == companyUserId
                                                                            )
                                                                            .FirstOrDefault().YearsExperience
                                                                            ,
                                                                            out auxYearsExperience
                                                                        )
                                                                        &&
                                                                        double.Parse(candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).FirstOrDefault().YearsExperience.Replace(".", ",")) == 0
                                                                        &&
                                                                        searchObject.JobExperienceId == 1
                                                                        &&
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).FirstOrDefault() == null
                                                                    )
                                                                    ||
                                                                    (
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ) != null
                                                                        &&
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).Count() > 0
                                                                        &&
                                                                        !culture.Name.Contains("es-")
                                                                        &&
                                                                        !string.IsNullOrEmpty
                                                                        (
                                                                            candidate.CompanyDescriptionList
                                                                            .Where
                                                                            (
                                                                                companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                            )
                                                                            .FirstOrDefault().YearsExperience
                                                                        )
                                                                        &&
                                                                        double.TryParse
                                                                        (
                                                                            candidate.CompanyDescriptionList
                                                                            .Where
                                                                            (
                                                                                companyDescription
                                                                                =>
                                                                                companyDescription.CompanyUserId == companyUserId
                                                                            )
                                                                            .FirstOrDefault().YearsExperience
                                                                            ,
                                                                            out auxYearsExperience
                                                                        )
                                                                        &&
                                                                        double.Parse(candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).FirstOrDefault().YearsExperience) == 0
                                                                        &&
                                                                        searchObject.JobExperienceId == 1
                                                                        &&
                                                                        candidate.CompanyDescriptionList.Where
                                                                        (
                                                                            companyDescription => companyDescription.CompanyUserId == companyUserId
                                                                        ).FirstOrDefault() == null
                                                                    )
                                                                )
                                                            )
                                                        )
                                                    )
                                                )
                                            )

                                            &&

                        #endregion

                            #region Is Featured

                            candidate.BasicInformation != null
                            &&
                            (
                                !searchObject.IsPotential
                                ||
                                (
                                    searchObject.IsPotential
                                    &&
                                    candidate.CandidateCompanies != null
                                    &&
                                    candidate.CandidateCompanies.Count > 0
                                    &&
                                    candidate.CandidateCompanies.Any
                                    (
                                        candidateCompany
                                        =>
                                        candidateCompany.CompanyUserId == companyUserId
                                        &&
                                        candidateCompany.IsPotential == true
                                    )
                                )
                            )

                            #endregion
                        )
                    )

                    .ToList();

                    #region Evaluations

                    if (searchObject.EvaluationFilter != 0)
                    {
                        List<Evaluation> evaluations =
                            await _contextCompany.Evaluation
                            .Where
                            (
                                evaluation
                                =>
                                evaluation.CompanyUserId == companyUserId
                            )
                            .Include(evaluation => evaluation.Evaluation_EvaluationCriteria)
                            .AsNoTracking()
                            .ToListAsync();

                        switch (searchObject.EvaluationFilter)
                        {
                            case 1: // Without Evaluation
                                candidatesList = candidatesList

                                .Where
                                (
                                    candidate =>
                                    (
                                        candidate.BasicInformation != null
                                        &&
                                        !evaluations
                                        .Any
                                        (
                                            evaluation
                                            =>
                                            evaluation.CandidateId == candidate.CandidateId
                                        )
                                    )
                                )

                                .ToList();

                                break;
                            case 2: // With Evaluation
                                candidatesList = candidatesList

                                .Where
                                (
                                    candidate =>
                                    (
                                        candidate.BasicInformation != null
                                        &&
                                        evaluations
                                        .Any
                                        (
                                            evaluation
                                            =>
                                            evaluation.CandidateId == candidate.CandidateId
                                        )
                                    )
                                )

                                .ToList();

                                break;
                            case 3: // Red face
                                candidatesList = candidatesList

                                .Where
                                (
                                    candidate =>
                                    (
                                        candidate.BasicInformation != null
                                        &&
                                        evaluations
                                        .Any
                                        (
                                            evaluation
                                            =>
                                            evaluation.CandidateId == candidate.CandidateId
                                        )
                                    )
                                )

                                .ToList();

                                candidatesList = await CandidatesFilterByColourFlag(candidatesList, companyUserId, 1, token);

                                break;
                            case 4: // Yellow face
                                candidatesList = candidatesList

                                .Where
                                (
                                    candidate =>
                                    (
                                        candidate.BasicInformation != null
                                        &&
                                        evaluations
                                        .Any
                                        (
                                            evaluation
                                            =>
                                            evaluation.CandidateId == candidate.CandidateId
                                        )
                                    )
                                )

                                .ToList();

                                candidatesList = await CandidatesFilterByColourFlag(candidatesList, companyUserId, 2, token);

                                break;
                            case 5: // Green face
                                candidatesList = candidatesList

                                .Where
                                (
                                    candidate =>
                                    (
                                        candidate.BasicInformation != null
                                        &&
                                        evaluations
                                        .Any
                                        (
                                            evaluation
                                            =>
                                            evaluation.CandidateId == candidate.CandidateId
                                        )
                                    )
                                )

                                .ToList();

                                candidatesList = await CandidatesFilterByColourFlag(candidatesList, companyUserId, 3, token);

                                break;
                            default:
                                break;
                        };
                    }

                    #endregion

                    #endregion

                    #region Count After Filters

                    totalCount = candidatesList.Count();

                    #endregion

                    #region Filter Paginator

                    candidatesList = candidatesList

                    .Skip((searchObject.Page) * searchObject.PageSize).Take(searchObject.PageSize)

                    .ToList();

                    #endregion
                }

                #endregion

                /* End Mapping */

                Dictionary<string, dynamic> resultObject = new Dictionary<string, dynamic>();

                resultObject["totalCount"] = totalCount;
                resultObject["candidatesList"] = candidatesList;

                return resultObject;
            }
            catch (Exception ex)
            {

                Dictionary<string, dynamic> resultObject = new Dictionary<string, dynamic>();

                resultObject["totalCount"] = 0;
                resultObject["candidatesList"] = new List<Candidate>();

                return resultObject;
            }
        }

        /**/

        public async Task<Dictionary<string, dynamic>> GetCandidatesByFilterAndJob
        (
            SearchByIdAndTextWithPaginationDTO searchObject,
            int companyUserId,
            CultureInfo culture,
            string token
        )
        {
            List<Candidate> candidatesList = [];

            #region Date formats


            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt",
                                            "M/dd/yyyy HH:mm:ss", "M/d/yyyy HH:mm:ss", "MM/d/yyyy HH:mm:ss"};

            #endregion

            #region Years Experience

            double experienceLowerLimit = 0;
            double experienceUpperLimit = 0;

            if (searchObject.JobExperienceId != 0)
            {
                switch (searchObject.JobExperienceId)
                {
                    case 1:
                        experienceLowerLimit = 0;
                        experienceUpperLimit = 0;
                        break;
                    case 2:
                        experienceLowerLimit = 1;
                        experienceUpperLimit = 3;
                        break;
                    case 3:
                        experienceLowerLimit = 3;
                        experienceUpperLimit = 5;
                        break;
                    case 4:
                        experienceLowerLimit = 5;
                        experienceUpperLimit = 7;
                        break;
                    case 5:
                        experienceLowerLimit = 7;
                        experienceUpperLimit = 9;
                        break;
                    case 6:
                        experienceLowerLimit = 9;
                        experienceUpperLimit = double.MaxValue;
                        break;
                    default:
                        break;
                }
            }

            #endregion

            try
            {
                #region Total Count Variable

                int totalCount = 0;

                #endregion

                #region Normalize Text

                searchObject.Text = searchObject.Text.ToLower().TrimStart().TrimEnd()
                .Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u");

                #endregion

                #region Aux Variables

                double auxYearsExperience = 0;

                #endregion

                #region Candidates Filter Job

                if (!searchObject.Ascending)
                {
                    #region Filter Descending Job

                    candidatesList = await _entities

                    .Include(candidate => candidate.BasicInformation)
                    .ThenInclude(basicInformation => basicInformation.Emails)

                    .Include(candidate => candidate.CandidateCompanies)

                    .Include(candidate => candidate.Candidate_Language)
                    .ThenInclude(candidate_language => candidate_language.Language)

                    .Include(candidate => candidate.Candidate_Language)
                    .ThenInclude(candidate_language => candidate_language.LanguageLevel)

                    .Include(candidate => candidate.Candidate_Postulation)

                    .Include(candidate => candidate.Candidate_TalentGroup)

                    .Include(candidate => candidate.Candidate_TechnicalAbilityList)
                    .ThenInclude(technicalAbility => technicalAbility.TechnicalAbilityTechnology)

                    .Include(candidate => candidate.Candidate_TechnicalAbilityList)
                    .ThenInclude(technicalAbility => technicalAbility.TechnicalAbilityLevel)

                    .Include(candidate => candidate.Candidate_Source)

                    .Include(candidate => candidate.StudyList)

                    .Include(candidate => candidate.Candidate_Tag)

                    .Include(candidate => candidate.CompanyDescriptionList)

                    .Include(candidate => candidate.WorkExperienceList)

                    .Where
                    (
                            #region Basic Validations

                                candidate =>
                                (
                                    (
                                        candidate.Candidate_Postulation != null
                                        &&
                                        candidate.Candidate_Postulation.Count > 0
                                        &&
                                        candidate.Candidate_Postulation.Any
                                        (
                                            candidate_postulation => candidate_postulation.JobId == searchObject.Id
                                        )
                                    )
                                    &&
                                    candidate.Candidate_Postulation.Any
                                    (
                                        candidate_postulation => candidate_postulation.CompanyUserId == companyUserId
                                        //&&
                                        //(
                                        //    candidate_postulation.JobPostingStatusId == 2
                                        //    ||
                                        //    candidate_postulation.JobPostingStatusId == 3
                                        //)
                                    )
                                )

                                    &&

                                #endregion

                            #region Search Text

                                (
                                    (
                                        !string.IsNullOrEmpty(candidate.Email)
                                        &&
                                        candidate.Email.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                            .Contains(searchObject.Text)
                                        &&
                                        searchObject.JobExperienceId == 0
                                        &&
                                        searchObject.JobProfessionId == 0
                                        &&
                                        (searchObject.TechnicalAbilities == null || searchObject.TechnicalAbilities.Count == 0)
                                        &&
                                        (searchObject.Tags == null || searchObject.Tags.Count == 0)
                                        &&
                                        (searchObject.Sources == null || searchObject.Sources.Count == 0)
                                        &&
                                        (searchObject.Languages == null || searchObject.Languages.Count == 0)
                                        &&
                                        (searchObject.SalaryAspirations == null || searchObject.SalaryAspirations.Count == 0)
                                        &&
                                        (searchObject.Countries == null || searchObject.Countries.Count == 0)
                                        &&
                                        (searchObject.Companies == null || searchObject.Companies.Count == 0)
                                    )
                                    ||
                                    (
                                        (candidate.BasicInformation != null)
                                        &&
                                        (
                                            candidate.Email.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                .Contains(searchObject.Text)
                                            ||
                                            (
                                                candidate.BasicInformation != null && !string.IsNullOrEmpty(candidate.BasicInformation.Name)
                                                &&
                                                candidate.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                    .Contains(searchObject.Text)
                                            )
                                            ||
