                                                &&
                                                !string.IsNullOrEmpty(candidate.BasicInformation.Surname)
                                                &&
                                                (
                                                    candidate.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                        .TrimEnd()
                                                    +
