                                                &&
                                                candidate.BasicInformation.Phone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                    .Contains(searchObject.Text)
                                            )
                                        )
                                        ||
                                        (
                                            candidate.BasicInformation != null && candidate.BasicInformation.Emails != null
                                            &&
                                            candidate.BasicInformation.Emails.Any
                                            (
                                                email => !string.IsNullOrEmpty(email.Mail)
                                                &&
                                                email.Mail.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                    .Contains(searchObject.Text)
                                                &&
                                                email.CompanyUserId == companyUserId
                                            )
                                        )
                                    )
                                )

                                &&

                            #endregion

                            #region Technology

                            (
                                (
                                    (
                                        (
