                                            ||
                                            searchObject.Countries.Count == 0
                                        )
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.Countries != null
                                            &&
                                            searchObject.Countries.Count > 0
                                        )
                                        &&
                                        (
