                            #endregion

                            #region Tags

                            (
                                (
                                    (
                                        (
                                            searchObject.Tags == null
                                            ||
                                            searchObject.Tags.Count == 0
                                        )
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.Tags != null
                                            &&
                                            searchObject.Tags.Count > 0
                                        )
                                        &&
                                        (
                                            candidate.Candidate_Tag != null
                                            &&
                                            candidate.Candidate_Tag.Count > 0
                                        )
                                    )
                                )
                            )

                            &&

                            #endregion

                            #region Sources

                            (
                                (
                                    (
                                        (
                                            searchObject.Sources == null
                                            ||
                                            searchObject.Sources.Count == 0
                                        )
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.Sources != null
                                            &&
                                            searchObject.Sources.Count > 0
                                        )
                                        &&
                                        (
                                            candidate.Candidate_Source != null
                                            &&
                                            candidate.Candidate_Source.Count > 0
                                        )
                                    )
                                )
                            )

                            &&

                                #endregion

                            #region Years Experience

                            (
                                (
                                    (
                                        searchObject.JobExperienceId == 0
                                        ||
                                        searchObject.JobExperienceId == 1
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.JobExperienceId > 0
                                        )
                                        &&
                                        (
                                            (
                                                candidate.ExperienceCount != null
                                                &&
                                                !string.IsNullOrEmpty(candidate.ExperienceCount.Years)
                                            )
                                            ||
                                            (
                                                candidate.CompanyDescriptionList != null
                                                &&
                                                candidate.CompanyDescriptionList.Count > 0
                                            )
                                        )
                                    )
                                )
                            )

                            #endregion
                    )

                    .OrderByDescending(candidate => candidate.CreationDateNoText)

                    .AsSplitQuery()

                    .ToListAsync();

                    candidatesList = candidatesList

                    .Where
                    (
                        candidate =>
                        (
