                                        searchObject.TechnicalAbilities == null
                                        ||
                                        searchObject.TechnicalAbilities.Count == 0
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.TechnicalAbilities != null
                                            &&
                                            searchObject.TechnicalAbilities.Count > 0
                                        )
                                        &&
                                        (
                                            (
                                                candidate.BasicInformation != null
                                            )
                                            &&
                                            (
                                                searchObject.TechnicalAbilities != null
                                                &&
                                                searchObject.TechnicalAbilities.Count > 0
                                                &&
                                                candidate.Candidate_TechnicalAbilityList != null
                                                &&
                                                candidate.Candidate_TechnicalAbilityList.Count > 0
                                                &&
                                                searchObject.TechnicalAbilities.All
                                                (
