                                                            candidate_technicalAbility.TechnicalAbilityTechnologyId == candidate_technicalAbilityFromSearch.TechnicalAbilityTechnologyId
                                                            &&
                                                            candidate_technicalAbility.TechnicalAbilityLevelId == candidate_technicalAbilityFromSearch.TechnicalAbilityLevelId
                                                    )
