                                    ||
                                    (
                                        searchObject.JobProfessionId > 0
                                        &&
                                        (
                                            candidate.BasicInformation != null
                                            &&
                                            (
                                                candidate.StudyList != null
                                                &&
                                                candidate.StudyList.Count > 0
                                                &&
                                                candidate.StudyList.Any(study => study.JobProfessionId == searchObject.JobProfessionId)
                                            )
                                        )
                                    )
                                )

                                &&

                            #endregion

                            #region Companies

                                (
                                    (
                                        searchObject.Companies == null
                                        ||
                                        searchObject.Companies.Count == 0
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.Companies != null
                                            &&
                                            searchObject.Companies.Count > 0
                                        )
                                        &&
                                        (
                                            (
                                                candidate.WorkExperienceList != null
                                                &&
                                                candidate.WorkExperienceList.Count > 0
                                            )
                                            &&
                                            (
                                                searchObject.Companies.All(character => candidate.WorkExperienceList
                                                    .Any
                                                    (
                                                        workExperience =>
                                                            workExperience.Company.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                            ==
                                                            character.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u")
                                                    )
                                                )
                                            )
                                        )
                                    )
                                )

                                &&

                            #endregion

                            #region Languages

                                (
                                    (
                                        searchObject.Languages == null
                                        ||
                                        searchObject.Languages.Count == 0
                                    )
                                    ||
                                    (
                                        (
                                            searchObject.Languages != null
                                            &&
                                            searchObject.Languages.Count > 0
                                        )
                                        &&
                                        (
                                            candidate.Candidate_Language != null
                                            &&
                                            candidate.Candidate_Language.Count > 0
                                            &&
                                            searchObject.Languages.All
                                            (
