            }
            catch (Exception ex)
            {
                string innerMessage = ex.InnerException != null ? ex.InnerException.Message : string.Empty;

                Console.WriteLine("Error de fechas: " + ex.Message + ", " + innerMessage);

                Dictionary<string, dynamic> resultObject = new Dictionary<string, dynamic>();

                resultObject["totalCount"] = 0;
                resultObject["candidatesList"] = new List<Candidate>();

                return resultObject;
            }
        }

