                resultObject["candidatesList"] = new List<Candidate>();

                return resultObject;
            }
        }

        /**/

        public async Task<List<Candidate>> CandidatesFilterByColourFlag(List<Candidate> candidatesList, int companyUserId, int colourFlagByFilter, string token)
        {
            try
            {
                PercentCriteria percentCriteria = await _percentCriteriaRepository.GetByCompanyUserId(companyUserId);

                List<int> candidateIds = candidatesList.Select(candidate => candidate.CandidateId).ToList();

                List<PostulationJobNameDTO> postulations =
                    await _postulationService.GetAllPostulationsWithJobNameAndEvaluations(candidateIds, percentCriteria, token);

                List<CandidateTalentGroupNameDTO> talentGroups =
                    await _candidate_TalentGroupService.GetAllCandidateTalentGroupsWithNameAndEvaluations(candidateIds, percentCriteria, token);

                List<Candidate> candidatesAux = [];

                foreach (Candidate candidate in candidatesList)
                {
                    int colourFlag = 0;

                    List<PostulationJobNameDTO> jobs = [];
                    List<CandidateTalentGroupNameDTO> talents = [];

                    string photo = string.Empty;
                    string init = string.Empty;
                    string name = string.Empty;

                    List<string> jobNames = [];
                    List<string> talentNames = [];

                    int jobCount = 0;
                    int talentCount = 0;

                    if (postulations != null && postulations.Count > 0)
                    {
                        jobs = postulations
                            .AsParallel()
                            .Where
                            (
                                postulationJobName => postulationJobName.CandidateId == candidate.CandidateId
                            )
                            .ToList();

                        if (jobs != null && jobs.Count > 0)
                        {
                            foreach (PostulationJobNameDTO job in jobs)
                            {
                                if (job != null)
                                    jobNames.Add(job.JobName);
                            }

                            jobCount = jobNames.Count();
                        }
                    }

                    if (talentGroups != null && talentGroups.Count > 0)
                    {
                        talents = talentGroups.Where(candidateTalentGroupName => candidateTalentGroupName.CandidateId == candidate.CandidateId).ToList();

                        if (talents != null && talents.Count > 0)
                        {
                            foreach (var talent in talents)
                            {
                                if (talent != null)
                                    talentNames.Add(talent.TalentGroupName);
                            }

                            talentCount = talentNames.Count();
                        }
                    }

                    if (jobs != null && jobs.Count > 0)
                    {
                        jobs.OrderByDescending(postulationJobName => postulationJobName.CreationDate).ToList();

                        colourFlag = jobs[0].ColourFlag;
                    }

                    if (colourFlag == 0 && talents != null && talents.Count > 0)
                    {
                        talents.OrderByDescending(x => x.CreationDate).ToList();

                        colourFlag = talents[0].ColourFlag;
                    }

                    if (colourFlag == colourFlagByFilter)
                        candidatesAux.Add(candidate);
                }

                return candidatesAux;
            }
            catch (Exception ex)
            {
                return null;
            }
        }

        /**/

        public async Task<List<Candidate>> GetCandidatesByFilterMaster(string search)
        {
            search = search.ToLower().TrimStart().TrimEnd()
                .Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u");

            List<Candidate> candidatesList = await _entities.Include(x => x.BasicInformation).ThenInclude(x => x.Currency)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Phones)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.Language)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.LanguageLevel)
                .Include(y => y.LanguageOther)
                .Include(x => x.Candidate_LanguageOther).ThenInclude(y => y.LanguageLevel)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(y => y.TechnicalAbilityLevel)
                .Include(x => x.WorkExperienceList)
                .Include(x => x.StudyList)
                .Where(x => (x.IsMigrated == 0 || (x.IsMigrated != 0 && x.IsFromCompanyAndLogin == true)) &&
                (
                   x.Email.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || (x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd() + " " + x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd()).Contains(search)
                || x.BasicInformation.Phone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Cellphone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Emails.Any(y => y.Mail.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.BasicInformation.Phones.Any(y => y.Number.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
