                || x.Candidate_TechnicalAbilityList.Any(y => y.Other.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search) && y.IsFromEmpresaAdded != true)
                || x.Candidate_TechnicalAbilityList.Any(y => y.TechnicalAbilityLevel.Level.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
