        public async Task<List<Candidate>> GetCandidatesWithIdsAndSearch(List<int> candidateIds, string search)
        {
            search = search.ToLower().TrimStart().TrimEnd()
                .Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u");
            List<Candidate> candidates = new List<Candidate>();
            foreach (int id in candidateIds)
            {
                Candidate candidate = await _entities.Include(x => x.BasicInformation).ThenInclude(x => x.Currency)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Phones)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.Language)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.LanguageLevel)
                .Include(y => y.LanguageOther)
                .Include(x => x.Candidate_LanguageOther).ThenInclude(y => y.LanguageLevel)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(y => y.TechnicalAbilityLevel)
                .Include(x => x.WorkExperienceList)
                .Include(x => x.StudyList)
                .Where(x => x.CandidateId == id && (
                x.Email.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                | (x.BasicInformation.Name.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd() + " " + x.BasicInformation.Surname.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").TrimEnd()).Contains(search) || x.BasicInformation.Phone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Phone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Cellphone.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.Candidate_Language.Any(y => y.Language.LanguageName.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.Candidate_Language.Any(y => y.LanguageLevel.LanguageLevelName.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.LanguageOther.Any(y => y.LanguageOtherName.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.Candidate_TechnicalAbilityList.Any(y => y.Discipline.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.Candidate_TechnicalAbilityList.Any(y => y.Other.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.Candidate_TechnicalAbilityList.Any(y => y.TechnicalAbilityLevel.Level.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.BasicInformation.SalaryAspiration.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.Currency.ShortName.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.BasicInformation.SalaryAspirationFromCompany.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)
                || x.WorkExperienceList.Any(y => y.Position.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.WorkExperienceList.Any(y => y.Functions.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.StudyList.Any(y => y.OtherJobProfession.ToLower().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search))
                || x.BasicInformation.Emails.Any(y => y.Mail.ToLower().Trim().Replace("á", "a").Replace("é", "e").Replace("í", "i").Replace("ó", "o").Replace("ú", "u").Replace("ü", "u").Contains(search)) || x.BasicInformation.Phones.Any(y => y.Number.ToLower().Contains(search))
                ))
                .AsNoTracking().FirstOrDefaultAsync();
                if (candidate != null)
                    candidates.Add(candidate);
            }
            return candidates;
        }

