                        x.BasicInformation.State == state
                        &&
                        x.BasicInformation.City == city
                    )
                    ||
                    (
                        x.CandidateCompanies != null
                        &&
                        x.CandidateCompanies.Count > 0
                        &&
                        x.CandidateCompanies.Any
                        (
                            y =>
                            y.Country == country
                            &&
                            y.State == state
                            &&
                           y.City == city
                        )
                    )
                ).ToList();
            }

            if (isSalaryAspirationFilter && !isFullSalaryAspirations)
            {
                candidateList = candidateList.Where
                (
                    x =>
                    (
                    salaryAspirationFilter != null
                    &&
                    salaryAspirationFilter.Count > 0
                    &&
                    (
                        (
                            x.BasicInformation != null
                            &&
                            x.BasicInformation.SalaryAspiration != null
                            &&
                            !string.IsNullOrEmpty(x.BasicInformation.SalaryAspiration)
                            &&
                            (
                                (
                                    salaryAspirationFilter
                                    .Any
                                    (
                                        s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) == 0
                                        &&
                                        x.BasicInformation.CurrencyId == s.CurrencyId
                                    )
                                )
                                ||
                                (
                                    salaryAspirationFilter
                                    .Any
                                    (
                                        s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", ""))
                                    <= int.Parse(x.BasicInformation.SalaryAspiration.Replace(".", "").Replace(",", ""))
                                        &&
                                        int.Parse(s.CurrencyUpperValue.Replace(".", "").Replace(",", ""))
                                        >= int.Parse(x.BasicInformation.SalaryAspiration.Replace(".", "").Replace(",", ""))
                                        &&
                                        x.BasicInformation.CurrencyId == s.CurrencyId
                                    )
                                )
                            )
                        )
                        ||
                        (
                            x.CandidateCompanies != null
                            &&
                            x.CandidateCompanies.Where(x => x.CompanyUserId == companyUserId).FirstOrDefault() != null
                            &&
                            !string.IsNullOrEmpty(x.CandidateCompanies.Where(x => x.CompanyUserId == companyUserId).FirstOrDefault().SalaryAspiration)
                            &&
                            (
                                (
                                    salaryAspirationFilter
                                    .Any
                                    (
                                        s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) == 0
                                        &&
                                        x.CandidateCompanies.Where(x => x.CompanyUserId == companyUserId).FirstOrDefault().CurrencyId == s.CurrencyId
                                    )
                                )
                                ||
                                (
                                    salaryAspirationFilter
                                    .Any
                                    (
                                        s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) <=
                                        int.Parse(x.CandidateCompanies
                                        .Where(x => x.CompanyUserId == companyUserId).FirstOrDefault().SalaryAspiration.Replace(".", "").Replace(",", ""))
                                        &&
                                        int.Parse(s.CurrencyUpperValue.Replace(".", "").Replace(",", ""))
                                        >= int.Parse(x.CandidateCompanies
                                        .Where(x => x.CompanyUserId == companyUserId).FirstOrDefault().SalaryAspiration.Replace(".", "").Replace(",", ""))
                                        &&
                                        x.CandidateCompanies.Where(x => x.CompanyUserId == companyUserId).FirstOrDefault().CurrencyId == s.CurrencyId
                                    )
                                )
                            )
                        )
                    )
                )
                ||
                (
                    (
                        salaryAspirationFilter == null
                        ||
                        salaryAspirationFilter.Count == 0
                    )
                )
                ).ToList();
            }

            return candidateList;
        }

        public List<Candidate> GetAllCandidateMasterWithDate(DateTime leftDate, DateTime rightDate)
        {
            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt",
                                            "d/MM/yyyy h:mm:ss tt"};

            List<Candidate> candidateList = _entities
                .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Gender)
                .Include(x => x.CandidateCompanies)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(x => x.TechnicalAbilityLevel)
                .Include(x => x.Candidate_Language).ThenInclude(x => x.Language)
                .Include(x => x.Candidate_Language).ThenInclude(x => x.LanguageLevel)
                .Include(x => x.Candidate_LanguageOther).ThenInclude(x => x.LanguageLevel)
                .Include(x => x.WorkExperienceList)
                .ToList()
                .Where(x => DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture) >= leftDate
                && DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture) <= rightDate
                && (x.IsMigrated == 0 || (x.IsMigrated != 0 && x.IsFromCompanyAndLogin)))
                .ToList();

            return candidateList;
        }

        public List<Candidate> GetAllCandidateMasterWithDateAndFilter
        (
            bool isLanguagesFilter, bool isFullLanguages, List<Candidate_LanguageDTO> languagesFilter,
            bool isTechnicalAbilitiesFilter, bool isFullTechnicalAbilities, List<Candidate_TechnicalAbilityDTO> technicalAbilitiesFilter,
            bool isLocationFilter, bool isFullLocations, string country, string state, string city,
            bool isSalaryAspirationFilter, bool isFullSalaryAspirations, List<SalaryAspirationFromSearchDTO> salaryAspirationFilter
        )
        {
            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt",
                                            "d/MM/yyyy h:mm:ss tt"};

            List<Candidate> candidateList = new List<Candidate>();

            candidateList = _entities
                .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.Candidate_Language).ThenInclude(x => x.Language)
                .Include(x => x.Candidate_Language).ThenInclude(x => x.LanguageLevel)
                .Include(x => x.Candidate_LanguageOther).ThenInclude(x => x.LanguageLevel)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(x => x.TechnicalAbilityTechnology)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(x => x.TechnicalAbilityLevel)
                .Include(x => x.CandidateCompanies)
                .ToList()
                .Where
                (
                    x => x.IsMigrated == 0 || (x.IsMigrated != 0 && x.IsFromCompanyAndLogin)
                )
                .ToList();

            if (isLanguagesFilter && !isFullLanguages)
            {
                candidateList = candidateList.Where
                (
                    x => languagesFilter.All(l => x.Candidate_Language
                                    .Any(y => y.LanguageId == l.LanguageId && y.LanguageLevelId == l.LanguageLevelId))
                ).ToList();
            }

            if (isTechnicalAbilitiesFilter && !isFullTechnicalAbilities)
            {
                candidateList = candidateList.Where
                (
                    x => technicalAbilitiesFilter.All(t => x.Candidate_TechnicalAbilityList
                                    .Any(y => y.TechnicalAbilityTechnologyId == t.TechnicalAbilityTechnologyId && y.TechnicalAbilityLevelId == t.TechnicalAbilityLevelId))
                ).ToList();
            }

            if (isLocationFilter && !isFullLocations)
            {
                candidateList = candidateList.Where
                (
                    x =>
                    (
                        x.BasicInformation != null
                        &&
                        x.BasicInformation.Country == country
                        &&
                        x.BasicInformation.State == state
                        &&
                        x.BasicInformation.City == city
                    )
                    ||
                    (
                        x.CandidateCompanies != null
                        &&
                        x.CandidateCompanies.Count > 0
                        &&
                        x.CandidateCompanies.Any
                        (
                            y =>
                            y.Country == country
                            &&
                            y.State == state
                            &&
                           y.City == city
                        )
                    )
                ).ToList();
            }

            if (isSalaryAspirationFilter && !isFullSalaryAspirations)
            {
                candidateList = candidateList.Where
                (
                    x =>
                    (
                    salaryAspirationFilter != null
                    &&
                    salaryAspirationFilter.Count > 0
                    &&
                    (
                        (
                            x.BasicInformation != null
                            &&
                            !string.IsNullOrEmpty(x.BasicInformation.SalaryAspiration)
                            &&
                            (
                                salaryAspirationFilter
                                .Any
                                (
                                    s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) == 0
                                    &&
                                    x.BasicInformation.CurrencyId == s.CurrencyId
                                )
                            )
                            ||
                            (
                                salaryAspirationFilter
                                .Any
                                (
                                    s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", ""))
                                    <= int.Parse(x.BasicInformation.SalaryAspiration.Replace(".", "").Replace(",", ""))
                                    &&
                                    int.Parse(s.CurrencyUpperValue.Replace(".", "").Replace(",", ""))
                                    >= int.Parse(x.BasicInformation.SalaryAspiration.Replace(".", "").Replace(",", ""))
                                    &&
                                    x.BasicInformation.CurrencyId == s.CurrencyId
                                )
                            )
                        )
                        ||
                        (
                            x.CandidateCompanies != null
                            &&
                            x.CandidateCompanies.Count > 0
                            &&
                            (
                                salaryAspirationFilter
                                .Any
                                (
                                    s => int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) == 0
                                    &&
                                    x.CandidateCompanies.Any(sa => sa.CurrencyId != null && sa.CurrencyId == s.CurrencyId)
                                )
                            )
                            ||
                            (
                                salaryAspirationFilter
                                .Any
                                (
                                    s => x.CandidateCompanies.Any(sa =>
                                    !string.IsNullOrEmpty(sa.SalaryAspiration)
                                    && int.Parse(s.CurrencyLowerValue.Replace(".", "").Replace(",", "")) <=
                                    int.Parse(sa.SalaryAspiration.Replace(".", "").Replace(",", "")))
                                    &&
                                    x.CandidateCompanies.Any(sa => int.Parse(s.CurrencyUpperValue.Replace(".", "").Replace(",", ""))
                                    >= int.Parse(sa.SalaryAspiration.Replace(".", "").Replace(",", "")))
                                    &&
                                    x.CandidateCompanies.Any(sa => sa.CurrencyId == s.CurrencyId)
                                )
                            )
                        )
                    )
                )
                ||
                (
                    (
                        salaryAspirationFilter == null
                        ||
                        salaryAspirationFilter.Count == 0
                    )
                )
                ).ToList();
            }

            return candidateList;
        }

        public List<Candidate> GetAllCandidateCompanyWithDate(DateTime leftDate, DateTime rightDate, int companyUserId)
        {
            string[] validformats = new[] { "MM/dd/yyyy", "yyyy/MM/dd", "MM/dd/yyyy HH:mm:ss", "yyyy-MM-dd HH:mm:ss, fff",
                                            "MM/dd/yyyy hh:mm tt", "M/dd/yyyy h:mm:ss tt", "MM/d/yyyy h:mm:ss tt", "M/d/yyyy h:mm:ss tt",
                                            "dd/MM/yyyy hh:mm:ss tt","dd/MM/yyyy hh:mm:ss","dd/MM/yyyy h:mm:ss","dd/MM/yyyy h:mm:ss ff",
                                            "dd/MM/yyyy h:mm:ss tt","dd/MM/yyyy hh:mm:ss ff","M/dd/yyyy hh:mm:ss tt",
                                            "d/MM/yyyy h:mm:ss tt"};

            List<Candidate> candidateList = _entities.Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(x => x.TechnicalAbilityLevel)
                .ToList()
                .Where(x => DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture) >= leftDate
                && DateTime.ParseExact(x.CreationDate, validformats, CultureInfo.InvariantCulture) <= rightDate
