        public async Task<List<Candidate>> GetCandidateForCurrencyCompany(int currency, int companyUserId)
        {
            List<Candidate> candidatesList = await _entities.Include(x => x.BasicInformation).ThenInclude(x => x.Currency)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Emails)
                .Include(x => x.BasicInformation).ThenInclude(x => x.Phones)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.Language)
                .Include(x => x.Candidate_Language).ThenInclude(y => y.LanguageLevel)
                .Include(y => y.LanguageOther)
                .Include(x => x.Candidate_LanguageOther).ThenInclude(y => y.LanguageLevel)
                .Include(x => x.Candidate_TechnicalAbilityList).ThenInclude(y => y.TechnicalAbilityLevel)
                .Include(x => x.WorkExperienceList)
                .Include(x => x.StudyList)
                .Include(x => x.CandidateCompanies)
                .Where(x => x.CompanyUserId == companyUserId && x.CandidateCompanies.Any(x => x.CurrencyId == currency))
            .AsNoTracking()
            .ToListAsync();
            return candidatesList;
        }

        public async Task<Candidate> GetCandidateToRequest(string email)
        {
            Candidate candidate = await _entities.Include(X => X.BasicInformation).ThenInclude(x => x.Emails)
                .Where(x => x.Email.ToLower().Trim() == email.ToLower().Trim() || x.BasicInformation.Emails.Any(y => y.Mail.ToLower().Trim() == email.ToLower().Trim()))
                .FirstOrDefaultAsync();
            return candidate;
        }

        public async Task<Candidate> ChangeDeleteState(int candidateId, string MemberEmail)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId).Include(x => x.BasicInformation).FirstOrDefaultAsync();

            candidate.IsDeleteProccess = !candidate.IsDeleteProccess;
            candidate.EmailMemberDeleteProcess = MemberEmail.ToLower().Trim();
            candidate.DeleteDate = DateTime.Now.AddHours(-5).ToString("MM/dd/yyyy HH:mm:ss");

            candidate.FullDeleteDate = DateTime.Now.AddDays(4).AddHours(-5).ToString("MM/dd/yyyy HH:mm:ss");

            bool isEdited = await Update(candidate);

            return candidate;
        }

        public async Task<Candidate> ChangeViewSelectionFiles(int candidateId)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId).Include(x => x.BasicInformation).FirstOrDefaultAsync();

            candidate.IsAuthDocuments = !candidate.IsAuthDocuments;

            bool isEdited = await Update(candidate);

            return candidate;
        }

        public async Task<Candidate> ChangeViewHiringFiles(int candidateId)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId).Include(x => x.BasicInformation).FirstOrDefaultAsync();

            candidate.IsAuthDocumentsHiring = !candidate.IsAuthDocumentsHiring;

            bool isEdited = await Update(candidate);

            return candidate;
        }


        public async Task<Candidate> ChangeDeleteStateCandidate(int candidateId)
        {
            Candidate candidate = await _entities.Where(x => x.CandidateId == candidateId).Include(x => x.BasicInformation).FirstOrDefaultAsync();

            candidate.IsDeleteProccess = !candidate.IsDeleteProccess;
            candidate.EmailMemberDeleteProcess = null;
            candidate.DeleteDate = DateTime.Now.AddHours(-5).ToString("MM/dd/yyyy HH:mm:ss");
            candidate.FullDeleteDate = DateTime.Now.AddDays(4).AddHours(-5).ToString("MM/dd/yyyy HH:mm:ss");
            bool isEdited = await Update(candidate);
            return candidate;
        }

