        public async Task<List<Candidate>> GetCandidatesExceptEmail(string email, int companyUserId)
        {
            List<Candidate> candidates = await _entities.Where(x => x.Email.ToLower().Trim() != email.ToLower().Trim() && x.IsMigrated != 0 &&
                x.CompanyUserId == companyUserId && x.IsFromCompanyAndLogin == false)
                .Include(x => x.BasicInformation)
                .ThenInclude(y => y.Emails)
                .ToListAsync();

            return candidates;
        }

